            divisors.append(i)

    min_sum = float('inf')
    # Iterate over all subsets of divisors
    from itertools import combinations
    for r in range(1, len(divisors)+1):
        for subset in combinations(divisors, r):
            product = 1
            for num in subset:
                product *= num
            if product == n:
                # Check distinctness (they are divisors so already integers, and subset gives distinct)
                total_sum = sum(subset)
                if total_sum < min_sum:
                    min_sum = total_sum

    try:
